import { getValue } from './get-value.js';
import type { TruncationMode } from '../../../../../../../typography/text-ellipsis/TextEllipsis.js';
import { HeaderData } from '../../../types.js';
import { getHeaderTruncatedText } from '../../../utils/text-truncation-header.js';
import { HeaderValueFormatter } from '../types/header.js';

export const computeSubheaderDisplay = ({
  subheader,
  formatStrategy,
  availableWidth,
  truncationMode,
}: {
  subheader: HeaderData | undefined;
  formatStrategy: HeaderValueFormatter;
  availableWidth: number;
  truncationMode: TruncationMode;
}) => {
  const subheaderValue = getValue(subheader);
  const subheaderContent = subheaderValue
    ? formatStrategy(subheaderValue)
    : undefined;
  const shownSubheaderText = subheaderContent
    ? getHeaderTruncatedText(subheaderContent, availableWidth, truncationMode)
    : undefined;

  return {
    subheaderContent,
    shownSubheaderText,
    isSubheaderTruncated:
      !!subheaderContent && shownSubheaderText !== subheaderContent,
  };
};
